sourcesContent:
import React, { useState, useEffect } from 'react';
import { api } from '../services/api';

interface Diet {
  id: number;
  nombre: string;
  categoria_animal: string;
  proteina_porcentaje: number;
  energia_kcal: number;
  fibra_porcentaje: number;
  costo_por_kg: number;
  total_ingredientes: number;
}

interface Ingredient {
  id: number;
  nombre: string;
  tipo: string;
  proteina_porcentaje: number;
  energia_kcal: number;
  costo_por_kg: number;
  stock_actual: number;
  stock_minimo: number;
  nivel_stock: string;
}

interface FeedingRecord {
  id: number;
  ubicacion_nombre: string;
  dieta_nombre: string;
  cantidad_kg: number;
  fecha_suministro: string;
  costo_total: number;
  responsable_nombre: string;
}

const NutritionComplete: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'diets' | 'ingredients' | 'feeding' | 'conversion' | 'alerts'>('diets');
  const [diets, setDiets] = useState<Diet[]>([]);
  const [ingredients, setIngredients] = useState<Ingredient[]>([]);
  const [feedingRecords, setFeedingRecords] = useState<FeedingRecord[]>([]);
  const [alerts, setAlerts] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [showDietForm, setShowDietForm] = useState(false);
  const [showIngredientForm, setShowIngredientForm] = useState(false);
  const [showFeedingForm, setShowFeedingForm] = useState(false);
  const [locations, setLocations] = useState<any[]>([]);
  const [animals, setAnimals] = useState<any[]>([]);

  const [newDiet, setNewDiet] = useState({
    nombre: '',
    categoria_animal: 'lechon',
    proteina_porcentaje: 0,
    energia_kcal: 0,
    fibra_porcentaje: 0,
    descripcion: ''
  });

  const [newIngredient, setNewIngredient] = useState({
    nombre: '',
    tipo: 'cereal',
    proteina_porcentaje: 0,
    energia_kcal: 0,
    fibra_porcentaje: 0,
    costo_por_kg: 0,
    stock_actual: 0,
    stock_minimo: 0,
    proveedor: ''
  });

  const [newFeeding, setNewFeeding] = useState({
    ubicacion_id: '',
    dieta_id: '',
    cantidad_kg: 0,
    fecha_suministro: new Date().toISOString().split('T')[0],
    hora_suministro: new Date().toTimeString().slice(0, 5),
    observaciones: ''
  });

  useEffect(() => {
    loadInitialData();
  }, []);

  useEffect(() => {
    if (activeTab === 'diets') loadDiets();
    else if (activeTab === 'ingredients') loadIngredients();
    else if (activeTab === 'feeding') loadFeedingRecords();
    else if (activeTab === 'alerts') loadAlerts();
  }, [activeTab]);

  const loadInitialData = async () => {
    try {
      const [locationsRes, animalsRes] = await Promise.all([
        api.get('/locations'),
        api.get('/animals?estado=activo')
      ]);
      setLocations(locationsRes.data);
      setAnimals(animalsRes.data);
    } catch (error) {
      console.error('Error cargando datos iniciales:', error);
    }
  };

  const loadDiets = async () => {
    setLoading(true);
    try {
      const response = await api.get('/nutrition/diets');
      setDiets(response.data);
    } catch (error) {
      console.error('Error cargando dietas:', error);
    } finally {
      setLoading(false);
    }
  };

  const loadIngredients = async () => {
    setLoading(true);
    try {
      const response = await api.get('/nutrition/ingredients');
      setIngredients(response.data);
    } catch (error) {
      console.error('Error cargando ingredientes:', error);
    } finally {
      setLoading(false);
    }
  };

  const loadFeedingRecords = async () => {
    setLoading(true);
    try {
      const today = new Date();
      const weekAgo = new Date(today.getTime() - 7 * 24 * 60 * 60 * 1000);
      const response = await api.get(`/nutrition/feeding?fecha_inicio=${weekAgo.toISOString().split('T')[0]}&fecha_fin=${today.toISOString().split('T')[0]}`);
      setFeedingRecords(response.data);
    } catch (error) {
      console.error('Error cargando registros de alimentación:', error);
    } finally {
      setLoading(false);
    }
  };

  const loadAlerts = async () => {
    setLoading(true);
    try {
      const response = await api.get('/nutrition/inventory-alerts');
      setAlerts(response.data);
    } catch (error) {
      console.error('Error cargando alertas:', error);
    } finally {
      setLoading(false);
    }
  };

  const createDiet = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await api.post('/nutrition/diets', newDiet);
      setNewDiet({ nombre: '', categoria_animal: 'lechon', proteina_porcentaje: 0, energia_kcal: 0, fibra_porcentaje: 0, descripcion: '' });
      setShowDietForm(false);
      loadDiets();
    } catch (error) {
      console.error('Error creando dieta:', error);
    }
  };

  const createIngredient = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await api.post('/nutrition/ingredients', newIngredient);
      setNewIngredient({ nombre: '', tipo: 'cereal', proteina_porcentaje: 0, energia_kcal: 0, fibra_porcentaje: 0, costo_por_kg: 0, stock_actual: 0, stock_minimo: 0, proveedor: '' });
      setShowIngredientForm(false);
      loadIngredients();
    } catch (error) {
      console.error('Error creando ingrediente:', error);
    }
  };

  const registerFeeding = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await api.post('/nutrition/feeding', newFeeding);
      setNewFeeding({ ubicacion_id: '', dieta_id: '', cantidad_kg: 0, fecha_suministro: new Date().toISOString().split('T')[0], hora_suministro: new Date().toTimeString().slice(0, 5), observaciones: '' });
      setShowFeedingForm(false);
      loadFeedingRecords();
    } catch (error) {
      console.error('Error registrando alimentación:', error);
    }
  };

  const renderDiets = () => (
    <div className="diets-section">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
        <h3>📋 Formulación de Dietas</h3>
        <button 
          onClick={() => setShowDietForm(true)}
          style={{ padding: '8px 16px', backgroundColor: '#4caf50', color: 'white', border: 'none', borderRadius: '4px' }}
        >
          + Nueva Dieta
        </button>
      </div>

      {showDietForm && (
        <form onSubmit={createDiet} style={{ backgroundColor: '#f5f5f5', padding: '20px', borderRadius: '8px', marginBottom: '20px' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '15px' }}>
            <input
              type="text"
              placeholder="Nombre de la dieta"
              value={newDiet.nombre}
              onChange={(e) => setNewDiet({...newDiet, nombre: e.target.value})}
              required
            />
            <select
              value={newDiet.categoria_animal}
              onChange={(e) => setNewDiet({...newDiet, categoria_animal: e.target.value})}
            >
              <option value="lechon">Lechón</option>
              <option value="recria">Recría</option>
              <option value="desarrollo">Desarrollo</option>
              <option value="engorde">Engorde</option>
              <option value="reproductor">Reproductor</option>
            </select>
            <input
              type="number"
              step="0.1"
              placeholder="Proteína %"
              value={newDiet.proteina_porcentaje}
              onChange={(e) => setNewDiet({...newDiet, proteina_porcentaje: parseFloat(e.target.value)})}
            />
            <input
              type="number"
              placeholder="Energía kcal"
              value={newDiet.energia_kcal}
              onChange={(e) => setNewDiet({...newDiet, energia_kcal: parseInt(e.target.value)})}
            />
            <input
              type="number"
              step="0.1"
              placeholder="Fibra %"
              value={newDiet.fibra_porcentaje}
              onChange={(e) => setNewDiet({...newDiet, fibra_porcentaje: parseFloat(e.target.value)})}
            />
          </div>
          <textarea
            placeholder="Descripción"
            value={newDiet.descripcion}
            onChange={(e) => setNewDiet({...newDiet, descripcion: e.target.value})}
            style={{ width: '100%', marginTop: '15px', padding: '8px' }}
          />
          <div style={{ marginTop: '15px' }}>
            <button type="submit" style={{ marginRight: '10px', padding: '8px 16px', backgroundColor: '#2196f3', color: 'white', border: 'none', borderRadius: '4px' }}>Crear</button>
            <button type="button" onClick={() => setShowDietForm(false)} style={{ padding: '8px 16px', backgroundColor: '#f44336', color: 'white', border: 'none', borderRadius: '4px' }}>Cancelar</button>
          </div>
        </form>
      )}

      <div className="diets-grid" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '15px' }}>
        {diets.map(diet => (
          <div key={diet.id} className="diet-card" style={{ border: '1px solid #ddd', padding: '15px', borderRadius: '8px', backgroundColor: 'white' }}>
            <h4>{diet.nombre}</h4>
            <p><strong>Categoría:</strong> {diet.categoria_animal}</p>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px', fontSize: '0.9em' }}>
              <span>Proteína: {diet.proteina_porcentaje}%</span>
              <span>Energía: {diet.energia_kcal} kcal</span>
              <span>Fibra: {diet.fibra_porcentaje}%</span>
              <span>Costo: ${diet.costo_por_kg}/kg</span>
            </div>
            <p style={{ fontSize: '0.8em', color: '#666', marginTop: '10px' }}>Ingredientes: {diet.total_ingredientes}</p>
          </div>
        ))}
      </div>
    </div>
  );

  const renderIngredients = () => (
    <div className="ingredients-section">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
        <h3>🌾 Inventario de Ingredientes</h3>
        <button 
          onClick={() => setShowIngredientForm(true)}
          style={{ padding: '8px 16px', backgroundColor: '#4caf50', color: 'white', border: 'none', borderRadius: '4px' }}
        >
          + Nuevo Ingrediente
        </button>
      </div>

      {showIngredientForm && (
        <form onSubmit={createIngredient} style={{ backgroundColor: '#f5f5f5', padding: '20px', borderRadius: '8px', marginBottom: '20px' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))', gap: '15px' }}>
            <input type="text" placeholder="Nombre" value={newIngredient.nombre} onChange={(e) => setNewIngredient({...newIngredient, nombre: e.target.value})} required />
            <select value={newIngredient.tipo} onChange={(e) => setNewIngredient({...newIngredient, tipo: e.target.value})}>
              <option value="cereal">Cereal</option>
              <option value="proteico">Proteico</option>
              <option value="fibra">Fibra</option>
              <option value="mineral">Mineral</option>
              <option value="vitamina">Vitamina</option>
            </select>
            <input type="number" step="0.1" placeholder="Proteína %" value={newIngredient.proteina_porcentaje} onChange={(e) => setNewIngredient({...newIngredient, proteina_porcentaje: parseFloat(e.target.value)})} />
            <input type="number" placeholder="Energía kcal" value={newIngredient.energia_kcal} onChange={(e) => setNewIngredient({...newIngredient, energia_kcal: parseInt(e.target.value)})} />
            <input type="number" step="0.01" placeholder="Costo/kg" value={newIngredient.costo_por_kg} onChange={(e) => setNewIngredient({...newIngredient, costo_por_kg: parseFloat(e.target.value)})} />
            <input type="number" placeholder="Stock actual" value={newIngredient.stock_actual} onChange={(e) => setNewIngredient({...newIngredient, stock_actual: parseFloat(e.target.value)})} />
            <input type="number" placeholder="Stock mínimo" value={newIngredient.stock_minimo} onChange={(e) => setNewIngredient({...newIngredient, stock_minimo: parseFloat(e.target.value)})} />
            <input type="text" placeholder="Proveedor" value={newIngredient.proveedor} onChange={(e) => setNewIngredient({...newIngredient, proveedor: e.target.value})} />
          </div>
          <div style={{ marginTop: '15px' }}>
            <button type="submit" style={{ marginRight: '10px', padding: '8px 16px', backgroundColor: '#2196f3', color: 'white', border: 'none', borderRadius: '4px' }}>Crear</button>
            <button type="button" onClick={() => setShowIngredientForm(false)} style={{ padding: '8px 16px', backgroundColor: '#f44336', color: 'white', border: 'none', borderRadius: '4px' }}>Cancelar</button>
          </div>
        </form>
      )}

      <div className="ingredients-table" style={{ overflowX: 'auto' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ backgroundColor: '#f5f5f5' }}>
              <th style={{ padding: '10px', textAlign: 'left', border: '1px solid #ddd' }}>Nombre</th>
              <th style={{ padding: '10px', textAlign: 'left', border: '1px solid #ddd' }}>Tipo</th>
              <th style={{ padding: '10px', textAlign: 'left', border: '1px solid #ddd' }}>Stock</th>
              <th style={{ padding: '10px', textAlign: 'left', border: '1px solid #ddd' }}>Costo/kg</th>
              <th style={{ padding: '10px', textAlign: 'left', border: '1px solid #ddd' }}>Estado</th>
            </tr>
          </thead>
          <tbody>
            {ingredients.map(ingredient => (
              <tr key={ingredient.id}>
                <td style={{ padding: '10px', border: '1px solid #ddd' }}>{ingredient.nombre}</td>
                <td style={{ padding: '10px', border: '1px solid #ddd' }}>{ingredient.tipo}</td>
                <td style={{ padding: '10px', border: '1px solid #ddd' }}>{ingredient.stock_actual} kg</td>
                <td style={{ padding: '10px', border: '1px solid #ddd' }}>${ingredient.costo_por_kg}</td>
                <td style={{ padding: '10px', border: '1px solid #ddd' }}>
                  <span style={{
                    padding: '4px 8px',
                    borderRadius: '4px',
                    fontSize: '0.8em',
                    backgroundColor: ingredient.nivel_stock === 'bajo' ? '#ffebee' : ingredient.nivel_stock === 'medio' ? '#fff3e0' : '#e8f5e8',
                    color: ingredient.nivel_stock === 'bajo' ? '#f44336' : ingredient.nivel_stock === 'medio' ? '#ff9800' : '#4caf50'
                  }}>
                    {ingredient.nivel_stock === 'bajo' ? 'BAJO' : ingredient.nivel_stock === 'medio' ? 'MEDIO' : 'NORMAL'}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );

  const renderFeeding = () => (
    <div className="feeding-section">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
        <h3>🍽️ Registro de Alimentación</h3>
        <button 
          onClick={() => setShowFeedingForm(true)}
          style={{ padding: '8px 16px', backgroundColor: '#4caf50', color: 'white', border: 'none', borderRadius: '4px' }}
        >
          + Registrar Alimentación
        </button>
      </div>

      {showFeedingForm && (
        <form onSubmit={registerFeeding} style={{ backgroundColor: '#f5f5f5', padding: '20px', borderRadius: '8px', marginBottom: '20px' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '15px' }}>
            <select value={newFeeding.ubicacion_id} onChange={(e) => setNewFeeding({...newFeeding, ubicacion_id: e.target.value})} required>
              <option value="">Seleccionar ubicación</option>
              {locations.map(location => (
                <option key={location.id} value={location.id}>{location.nombre}</option>
              ))}
            </select>
            <select value={newFeeding.dieta_id} onChange={(e) => setNewFeeding({...newFeeding, dieta_id: e.target.value})} required>
              <option value="">Seleccionar dieta</option>
              {diets.map(diet => (
                <option key={diet.id} value={diet.id}>{diet.nombre}</option>
              ))}
            </select>
            <input type="number" step="0.1" placeholder="Cantidad (kg)" value={newFeeding.cantidad_kg} onChange={(e) => setNewFeeding({...newFeeding, cantidad_kg: parseFloat(e.target.value)})} required />
            <input type="date" value={newFeeding.fecha_suministro} onChange={(e) => setNewFeeding({...newFeeding, fecha_suministro: e.target.value})} required />
            <input type="time" value={newFeeding.hora_suministro} onChange={(e) => setNewFeeding({...newFeeding, hora_suministro: e.target.value})} />
          </div>
          <textarea placeholder="Observaciones" value={newFeeding.observaciones} onChange={(e) => setNewFeeding({...newFeeding, observaciones: e.target.value})} style={{ width: '100%', marginTop: '15px', padding: '8px' }} />
          <div style={{ marginTop: '15px' }}>
            <button type="submit" style={{ marginRight: '10px', padding: '8px 16px', backgroundColor: '#2196f3', color: 'white', border: 'none', borderRadius: '4px' }}>Registrar</button>
            <button type="button" onClick={() => setShowFeedingForm(false)} style={{ padding: '8px 16px', backgroundColor: '#f44336', color: 'white', border: 'none', borderRadius: '4px' }}>Cancelar</button>
          </div>
        </form>
      )}

      <div className="feeding-records">
        <h4>Registros Recientes (Última Semana)</h4>
        <div style={{ overflowX: 'auto' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr style={{ backgroundColor: '#f5f5f5' }}>
                <th style={{ padding: '10px', textAlign: 'left', border: '1px solid #ddd' }}>Fecha</th>
                <th style={{ padding: '10px', textAlign: 'left', border: '1px solid #ddd' }}>Ubicación</th>
                <th style={{ padding: '10px', textAlign: 'left', border: '1px solid #ddd' }}>Dieta</th>
                <th style={{ padding: '10px', textAlign: 'left', border: '1px solid #ddd' }}>Cantidad</th>
                <th style={{ padding: '10px', textAlign: 'left', border: '1px solid #ddd' }}>Costo</th>
                <th style={{ padding: '10px', textAlign: 'left', border: '1px solid #ddd' }}>Responsable</th>
              </tr>
            </thead>
            <tbody>
              {feedingRecords.map(record => (
                <tr key={record.id}>
                  <td style={{ padding: '10px', border: '1px solid #ddd' }}>{new Date(record.fecha_suministro).toLocaleDateString()}</td>
                  <td style={{ padding: '10px', border: '1px solid #ddd' }}>{record.ubicacion_nombre}</td>
                  <td style={{ padding: '10px', border: '1px solid #ddd' }}>{record.dieta_nombre}</td>
                  <td style={{ padding: '10px', border: '1px solid #ddd' }}>{record.cantidad_kg} kg</td>
                  <td style={{ padding: '10px', border: '1px solid #ddd' }}>${record.costo_total.toFixed(2)}</td>
                  <td style={{ padding: '10px', border: '1px solid #ddd' }}>{record.responsable_nombre}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );

  const renderAlerts = () => (
    <div className="alerts-section">
      <h3>⚠️ Alertas de Inventario</h3>
      {alerts.length === 0 ? (
        <p style={{ textAlign: 'center', color: '#4caf50', padding: '20px' }}>✅ No hay alertas de inventario</p>
      ) : (
        <div className="alerts-list">
          {alerts.map(alert => (
            <div 
              key={alert.id} 
              style={{
                padding: '15px',
                margin: '10px 0',
                borderRadius: '8px',
                border: '1px solid',
                borderColor: alert.nivel_alerta === 'critico' ? '#f44336' : alert.nivel_alerta === 'bajo' ? '#ff9800' : '#2196f3',
                backgroundColor: alert.nivel_alerta === 'critico' ? '#ffebee' : alert.nivel_alerta === 'bajo' ? '#fff3e0' : '#e3f2fd'
              }}
            >
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div>
                  <h4 style={{ margin: '0 0 5px 0' }}>{alert.nombre}</h4>
                  <p style={{ margin: '0', fontSize: '0.9em', color: '#666' }}>Stock actual: {alert.stock_actual} kg</p>
                  <p style={{ margin: '0', fontSize: '0.9em', color: '#666' }}>Stock mínimo: {alert.stock_minimo} kg</p>
                </div>
                <div style={{ textAlign: 'right' }}>
                  <div style={{
                    fontSize: '1.2em',
                    fontWeight: 'bold',
                    color: alert.nivel_alerta === 'critico' ? '#f44336' : alert.nivel_alerta === 'bajo' ? '#ff9800' : '#2196f3'
                  }}>
                    {alert.porcentaje_stock}%
                  </div>
                  <div style={{ fontSize: '0.8em', textTransform: 'uppercase' }}>
                    {alert.nivel_alerta}
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );

  return (
    <div className="nutrition-container">
      <div className="nutrition-header">
        <h2>🌾 Nutrición y Alimentación</h2>

        <div className="tab-navigation" style={{ marginBottom: '20px' }}>
          {[
            { key: 'diets', label: '📋 Dietas' },
            { key: 'ingredients', label: '🌾 Ingredientes' },
            { key: 'feeding', label: '🍽️ Alimentación' },
            { key: 'alerts', label: '⚠️ Alertas' }
          ].map(tab => (
            <button
              key={tab.key}
              onClick={() => setActiveTab(tab.key as any)}
              style={{
                padding: '10px 20px',
                margin: '0 5px',
                border: 'none',
                borderRadius: '5px',
                backgroundColor: activeTab === tab.key ? '#2196f3' : '#f5f5f5',
                color: activeTab === tab.key ? 'white' : '#333',
                cursor: 'pointer'
              }}
            >
              {tab.label}
            </button>
          ))}
        </div>
      </div>

      <div className="nutrition-content">
        {loading && <div style={{ textAlign: 'center', padding: '20px' }}>Cargando...</div>}

        {activeTab === 'diets' && renderDiets()}
        {activeTab === 'ingredients' && renderIngredients()}
        {activeTab === 'feeding' && renderFeeding()}
        {activeTab === 'alerts' && renderAlerts()}
      </div>
    </div>
  );
};

export default NutritionComplete;
